// Generate SRT captions from the daily video script.
// Uses the per-segment duration_seconds from the script to produce accurate
// time codes for each spoken block.
//
// SRT format:
//   <sequence>
//   <start> --> <end>
//   <text>
//   <blank line>
//
// Strategy:
//   1. Split each script segment's spoken text into ~4-second caption lines.
//   2. Assign cumulative timecodes based on declared segment durations.
//   3. Emit intro, all segments, and outro as separate caption groups.

const ctx = $input.first().json;
const script = ctx.video_script || ctx.script || {};

function secondsToSRT(totalSeconds) {
  const h = Math.floor(totalSeconds / 3600);
  const m = Math.floor((totalSeconds % 3600) / 60);
  const s = Math.floor(totalSeconds % 60);
  const ms = Math.round((totalSeconds - Math.floor(totalSeconds)) * 1000);
  return [
    String(h).padStart(2, '0'),
    String(m).padStart(2, '0'),
    String(s).padStart(2, '0'),
  ].join(':') + ',' + String(ms).padStart(3, '0');
}

// Split a block of text into caption lines of approximately targetWords words.
function splitIntoLines(text, wordsPerLine = 8) {
  const words = String(text || '').trim().split(/\s+/).filter(Boolean);
  const lines = [];
  for (let i = 0; i < words.length; i += wordsPerLine) {
    lines.push(words.slice(i, i + wordsPerLine).join(' '));
  }
  return lines.length > 0 ? lines : [String(text || '').trim()];
}

// Average spoken words per second (comfortable narration pace).
const WORDS_PER_SECOND = 2.5;

// Collect all spoken blocks: intro, segments, outro.
const blocks = [];

if (script.intro) {
  const duration = Math.max(
    String(script.intro).trim().split(/\s+/).length / WORDS_PER_SECOND,
    2
  );
  blocks.push({ text: String(script.intro).trim(), duration });
}

if (Array.isArray(script.segments)) {
  for (const seg of script.segments) {
    if (seg && seg.script) {
      const declaredDuration = typeof seg.duration_seconds === 'number' ? seg.duration_seconds : null;
      const estimatedDuration = String(seg.script).trim().split(/\s+/).length / WORDS_PER_SECOND;
      blocks.push({
        text: String(seg.script).trim(),
        duration: declaredDuration ?? estimatedDuration,
      });
    }
  }
}

if (script.outro) {
  const duration = Math.max(
    String(script.outro).trim().split(/\s+/).length / WORDS_PER_SECOND,
    2
  );
  blocks.push({ text: String(script.outro).trim(), duration });
}

// Build SRT entries.
const entries = [];
let sequence = 1;
let cursor = 0; // running time in seconds

for (const block of blocks) {
  const lines = splitIntoLines(block.text, 8);
  const lineDuration = block.duration / lines.length;

  for (const line of lines) {
    const start = cursor;
    const end = cursor + lineDuration;
    entries.push(
      `${sequence}\n${secondsToSRT(start)} --> ${secondsToSRT(end)}\n${line}`
    );
    sequence++;
    cursor = end;
  }
}

const totalDuration = cursor;
const captions_srt = entries.length > 0 ? entries.join('\n\n') + '\n' : null;
const captions_format = captions_srt ? 'srt' : 'none';

return [{
  json: {
    ...ctx,
    _captions_srt: captions_srt,
    _captions_format: captions_format,
    _render_total_duration: Math.round(totalDuration),
  }
}];

// Assemble the render job specification.
// Resolves the active render provider from n8n variables and builds
// the payload for the video render service.
//
// Supported providers (v1):
//   shotstack   — REST API, image slideshow + audio + SRT captions → MP4
//   creatomate  — REST API, template-based image+audio render → MP4
//   none        — no render credentials configured; assets are packaged
//                 but no external render call is made (fallback mode)
//
// Image assets: ctx.image_assets (from 06b)
// Narration:    ctx.narration_asset (from 06c)
// Captions:     ctx._captions_srt (from Generate Captions node)
// Script meta:  ctx.video_script.total_duration_seconds

const ctx = $input.first().json;
const imageAssets  = ctx.image_assets  || null;
const narration    = ctx.narration_asset || null;
const captionsSrt  = ctx._captions_srt  || null;
const script       = ctx.video_script   || ctx.script || {};

// Resolve provider.
const rawProvider = ($vars.RENDER_PROVIDER || '').trim().toLowerCase();
const SUPPORTED_PROVIDERS = ['shotstack', 'creatomate'];
const render_provider = SUPPORTED_PROVIDERS.includes(rawProvider) ? rawProvider : 'none';

// Duration: prefer declared script duration, else from captions generation.
const duration_seconds =
  (typeof script.total_duration_seconds === 'number' ? script.total_duration_seconds : null)
  ?? ctx._render_total_duration
  ?? null;

// --- Build Shotstack timeline ---
function buildShotstackPayload(ctx, imageAssets, narration, captionsSrt, duration_seconds) {
  const timeline = { tracks: [] };

  // Image track — one clip per image, evenly distributed across the duration.
  const images = (imageAssets && Array.isArray(imageAssets.images)) ? imageAssets.images : [];
  if (images.length > 0) {
    const clipDuration = duration_seconds
      ? Math.max(1, duration_seconds / images.length)
      : 10;
    const imageClips = images.map((img, i) => ({
      asset: {
        type: img.format === 'b64_json' ? 'image' : 'image',
        src: img.url || `data:${img.mime_type || 'image/png'};base64,${img.b64_json}`,
      },
      start: i * clipDuration,
      length: clipDuration,
      effect: 'zoomIn',
    }));
    timeline.tracks.push({ clips: imageClips });
  }

  // Audio track — narration audio.
  if (narration && narration.audio_b64) {
    timeline.tracks.push({
      clips: [{
        asset: {
          type: 'audio',
          src: `data:audio/${narration.audio_encoding || 'mp3'};base64,${narration.audio_b64}`,
          volume: 1,
        },
        start: 0,
        length: duration_seconds || 180,
      }]
    });
  }

  // Caption track — SRT subtitles.
  if (captionsSrt) {
    timeline.tracks.push({
      clips: [{
        asset: {
          type: 'html',
          html: '<p>{{caption}}</p>',
          css: 'p { font-family: Arial; font-size: 20px; color: #ffffff; text-shadow: 1px 1px 2px #000; text-align: center; }',
          width: 560,
          height: 80,
          position: 'bottom',
        },
        start: 0,
        length: duration_seconds || 180,
      }]
    });
  }

  const output = {
    format: 'mp4',
    resolution: 'hd',
    fps: 25,
    quality: 'mediocre',
    size: { width: 1280, height: 720 },
  };

  return { timeline, output };
}

// --- Build Creatomate payload ---
function buildCreatomatePayload(ctx, imageAssets, narration, captionsSrt, duration_seconds) {
  const images = (imageAssets && Array.isArray(imageAssets.images)) ? imageAssets.images : [];
  const modifications = {};

  if (images.length > 0) {
    modifications['Background Image'] = images[0].url
      || `data:${images[0].mime_type || 'image/png'};base64,${images[0].b64_json}`;
  }

  if (narration && narration.audio_b64) {
    modifications['Narration Audio'] =
      `data:audio/${narration.audio_encoding || 'mp3'};base64,${narration.audio_b64}`;
  }

  if (captionsSrt) {
    modifications['Captions'] = captionsSrt;
  }

  return {
    template_id: $vars.CREATOMATE_TEMPLATE_ID || '',
    modifications,
  };
}

let render_payload = null;
const warnings = [];

if (!imageAssets || !Array.isArray(imageAssets.images) || imageAssets.images.length === 0) {
  warnings.push('No image_assets available. Render will use placeholder images if the provider supports it.');
}
if (!narration || !narration.audio_b64) {
  warnings.push('No narration audio available. Render will be silent.');
}
if (!captionsSrt) {
  warnings.push('No captions generated. Video will not have subtitles.');
}

if (render_provider === 'shotstack') {
  render_payload = buildShotstackPayload(ctx, imageAssets, narration, captionsSrt, duration_seconds);
} else if (render_provider === 'creatomate') {
  render_payload = buildCreatomatePayload(ctx, imageAssets, narration, captionsSrt, duration_seconds);
} else {
  warnings.push(
    'No render provider configured (RENDER_PROVIDER not set or unsupported). ' +
    'Assets are ready but video was not rendered. ' +
    'Set RENDER_PROVIDER=shotstack and SHOTSTACK_API_KEY to enable rendering.'
  );
}

return [{
  json: {
    ...ctx,
    _render_provider: render_provider,
    _render_payload: render_payload,
    _render_duration_seconds: duration_seconds,
    _render_warnings: warnings,
  }
}];

// Fallback path: no render provider configured or provider is 'none'.
// Pass the context through with a failed render asset (assets packaged,
// no external render call made).
const ctx = $input.first().json;
return [{ json: { ...ctx, _render_response: null, _render_provider_used: 'none' } }];

// Normalize the Shotstack API response into the render_video_asset contract.
// Shotstack POST /render returns:
//   { success: true, message: '...', response: { id: 'ss-xxx', status: 'queued', ... } }
//   or an error object on failure.
//
// A queued job maps to status='pending' — the video_url becomes available
// after the webhook fires or when the job is polled.

const ctx = $input.first().json;
const raw = ctx._render_response || {};
const resp = raw.response || {};
const captionsSrt = ctx._captions_srt || null;
const warnings = Array.isArray(ctx._render_warnings) ? [...ctx._render_warnings] : [];

const render_job_id = resp.id || null;
const ss_status = (resp.status || '').toLowerCase();

// Map Shotstack status to our status enum.
const STATUS_MAP = { queued: 'pending', fetching: 'pending', rendering: 'pending', saving: 'pending', done: 'completed', failed: 'failed' };
const status = STATUS_MAP[ss_status] || (raw.success === false ? 'failed' : 'pending');

if (status === 'failed' || raw.success === false) {
  warnings.push(`Shotstack render failed: ${raw.message || resp.message || 'Unknown error'}`);
}

const render_video_asset = {
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  status,
  render_provider: 'shotstack',
  render_job_id,
  video_url: resp.url || null,
  duration_seconds: ctx._render_duration_seconds ?? null,
  captions_srt: captionsSrt,
  captions_format: captionsSrt ? 'srt' : 'none',
  image_count: ctx.image_assets?.image_count ?? null,
  has_narration: !!(ctx.narration_asset?.audio_b64),
  generated_at: new Date().toISOString(),
  warning: warnings.length > 0 ? warnings.join(' | ') : null,
};

const { _render_payload, _render_response, _render_provider, _render_warnings, ...cleanCtx } = ctx;
return [{ json: { ...cleanCtx, render_video_asset } }];

// Normalize the Creatomate API response into the render_video_asset contract.
// Creatomate POST /renders returns an array of render objects:
//   [{ id: 'cre-xxx', status: 'planned'|'rendering'|'succeeded'|'failed', url: '...', ... }]
//   or an error object on failure.

const ctx = $input.first().json;
const raw = ctx._render_response;
const captionsSrt = ctx._captions_srt || null;
const warnings = Array.isArray(ctx._render_warnings) ? [...ctx._render_warnings] : [];

// Creatomate returns an array; we take the first render result.
const renders = Array.isArray(raw) ? raw : (raw ? [raw] : []);
const result = renders[0] || {};

const render_job_id = result.id || null;
const cre_status = (result.status || '').toLowerCase();

const STATUS_MAP = { planned: 'pending', rendering: 'pending', succeeded: 'completed', failed: 'failed' };
const status = STATUS_MAP[cre_status] || (renders.length === 0 ? 'failed' : 'pending');

if (status === 'failed') {
  warnings.push(`Creatomate render failed: ${result.error_message || result.message || 'Unknown error'}`);
}

const render_video_asset = {
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  status,
  render_provider: 'creatomate',
  render_job_id,
  video_url: result.url || null,
  duration_seconds: ctx._render_duration_seconds ?? null,
  captions_srt: captionsSrt,
  captions_format: captionsSrt ? 'srt' : 'none',
  image_count: ctx.image_assets?.image_count ?? null,
  has_narration: !!(ctx.narration_asset?.audio_b64),
  generated_at: new Date().toISOString(),
  warning: warnings.length > 0 ? warnings.join(' | ') : null,
};

const { _render_payload, _render_response, _render_provider, _render_warnings, ...cleanCtx } = ctx;
return [{ json: { ...cleanCtx, render_video_asset } }];

// Fallback normalizer: no render provider was used.
// Emit a render_video_asset with status='failed' and a descriptive warning,
// but still include the generated captions so they are not lost.

const ctx = $input.first().json;
const captionsSrt = ctx._captions_srt || null;
const warnings = Array.isArray(ctx._render_warnings) ? [...ctx._render_warnings] : [];

if (warnings.length === 0) {
  warnings.push(
    'No render provider configured (RENDER_PROVIDER not set). ' +
    'Assets are ready but video was not rendered. ' +
    'Set RENDER_PROVIDER=shotstack and SHOTSTACK_API_KEY to enable rendering.'
  );
}

const render_video_asset = {
  topic_slug: ctx.topic_slug,
  date_key: ctx.date_key,
  status: 'failed',
  render_provider: 'none',
  render_job_id: null,
  video_url: null,
  duration_seconds: ctx._render_duration_seconds ?? null,
  captions_srt: captionsSrt,
  captions_format: captionsSrt ? 'srt' : 'none',
  image_count: ctx.image_assets?.image_count ?? null,
  has_narration: !!(ctx.narration_asset?.audio_b64),
  generated_at: new Date().toISOString(),
  warning: warnings.join(' | '),
};

const { _render_payload, _render_response, _render_provider, _render_warnings,
        _captions_srt, _captions_format, _render_total_duration, _render_duration_seconds,
        ...cleanCtx } = ctx;
return [{ json: { ...cleanCtx, render_video_asset } }];

// Merge render responses from Shotstack, Creatomate, or fallback path
// into a single downstream item.
// Exactly one path executes per run; pass it through unchanged.
const item = $input.first();
return [{ json: item.json }];
